import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { searchRentals, fetchStates, fetchPropertyTypes } from '../utils/api';
import { LoadingState, ErrorState, EmptyState } from '../components/LoadingState';
import Pagination from '../components/Pagination';

const SORT_COLUMNS = [
  { value: 'price', label: 'Price' },
  { value: 'bedrooms', label: 'Bedrooms' },
  { value: 'bathrooms', label: 'Bathrooms' },
  { value: 'parking_spaces', label: 'Parking' },
  { value: 'suburb', label: 'Suburb' },
];

const formatPrice = (p) =>
  p != null ? `$${Number(p).toLocaleString('en-AU')}/wk` : '—';

const normalizeRental = (r) => ({
  ...r,
  property_type: r.property_type || r.type || '—',
  parking_spaces: r.parking_spaces ?? r.parking ?? '—',
  price: r.price ?? r.weekly_rent ?? r.rent ?? null,
});

const SearchPage = () => {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();

  const [states, setStates] = useState([]);
  const [propertyTypes, setPropertyTypes] = useState([]);

  const [filters, setFilters] = useState({
    state: searchParams.get('state') || '',
    suburb: searchParams.get('suburb') || '',
    postcode: searchParams.get('postcode') || '',
    property_type: searchParams.get('property_type') || '',
    min_price: searchParams.get('min_price') || '',
    max_price: searchParams.get('max_price') || '',
    bedrooms: searchParams.get('bedrooms') || '',
    bathrooms: searchParams.get('bathrooms') || '',
    parking_spaces: searchParams.get('parking_spaces') || '',
    sort_col: searchParams.get('sort_col') || '',
    sort_order: searchParams.get('sort_order') || 'asc',
  });

  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(Number(searchParams.get('page')) || 1);

  const debounceRef = useRef(null);

  useEffect(() => {
    fetchStates().then(setStates).catch(() => {});
    fetchPropertyTypes().then(setPropertyTypes).catch(() => {});
  }, []);

  const doSearch = useCallback(async (currentFilters, currentPage) => {
    setLoading(true);
    setError(null);

    try {
      const params = { ...currentFilters, page: currentPage };

      Object.keys(params).forEach((k) => {
        if (params[k] === '' || params[k] == null) delete params[k];
      });

      const data = await searchRentals(params);
      setResults(data);
    } catch (err) {
      setError(err.message || 'Search failed.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);

    debounceRef.current = setTimeout(() => {
      doSearch(filters, page);

      const params = {};
      Object.entries(filters).forEach(([k, v]) => {
        if (v) params[k] = v;
      });

      if (page > 1) params.page = page;
      setSearchParams(params, { replace: true });
    }, 400);

    return () => clearTimeout(debounceRef.current);
  }, [filters, page]);

  const handleFilterChange = (key, value) => {
    setFilters((prev) => ({ ...prev, [key]: value }));
    setPage(1);
  };

  const rentalsRaw = results?.rentals || results?.data || [];

  const rentals = rentalsRaw.map(normalizeRental);

  const totalCount =
    results?.pagination?.total ||
    results?.total ||
    rentals.length;

  const totalPages =
    results?.pagination?.lastPage ||
    results?.lastPage ||
    1;

  return (
    <div className="search-page">

      {/* SIDEBAR */}
      <div className="search-page__sidebar">
        <div className="filter-panel">

          <h2>Filters</h2>

          <select
            value={filters.state}
            onChange={(e) => handleFilterChange('state', e.target.value)}
          >
            <option value="">All States</option>
            {states.map((s) => (
              <option key={s} value={s}>{s}</option>
            ))}
          </select>

          <select
            value={filters.property_type}
            onChange={(e) => handleFilterChange('property_type', e.target.value)}
          >
            <option value="">All Types</option>
            {propertyTypes.map((t) => (
              <option key={t} value={t}>{t}</option>
            ))}
          </select>

        </div>
      </div>

      {/* RESULTS */}
      <div className="search-page__results">

        <h1 className="results-header__title">
          {loading ? 'Searching…' : `${totalCount} results found`}
        </h1>

        {loading && <LoadingState message="Searching..." />}
        {error && <ErrorState message={error} />}

        {!loading && rentals.length === 0 && (
          <EmptyState icon="🏘️" title="No results" />
        )}

        <div className="results-table-wrapper">
          <table className="results-table">
            <thead>
              <tr>
                <th>Address</th>
                <th>Suburb</th>
                <th>State</th>
                <th>Type</th>
                <th>Bed</th>
                <th>Bath</th>
                <th>Park</th>
                <th>Price/wk</th>
              </tr>
            </thead>

            <tbody>
              {rentals.map((r) => (
                <tr
                  key={r.id}
                  onClick={() => navigate(`/rental/${r.id}`)}
                  className="results-table__row"
                >
                  <td>{r.address || '—'}</td>
                  <td>{r.suburb || '—'}</td>
                  <td>{r.state || '—'}</td>
                  <td>{r.property_type}</td>
                  <td>{r.bedrooms ?? '—'}</td>
                  <td>{r.bathrooms ?? '—'}</td>
                  <td>{r.parking_spaces}</td>
                  <td>{formatPrice(r.price)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <Pagination
          page={page}
          totalPages={totalPages}
          onPageChange={setPage}
        />
      </div>
    </div>
  );
};

export default SearchPage;
